# Build step for Mjolnir.jl
#
# Fetches the MIT-licensed community MATLAB grammar for tree-sitter (pinned), compiles
# it into a shared library under `runtime/`, locates the system tree-sitter runtime, and
# writes the resolved paths to `deps/deps.jl` (consumed at module load).
#
# Clean-room: only the grammar (MIT) is vendored/compiled; no MathWorks or GPL sources.

using Libdl

const GRAMMAR_URL = "https://github.com/acristoffers/tree-sitter-matlab"
const GRAMMAR_REV = "c2390a59016f74e7d5f75ef09510768b4f30217e"  # pinned for reproducibility

const PKGROOT = normpath(joinpath(@__DIR__, ".."))
const BUILDDIR = joinpath(@__DIR__, "build")
const GRAMMARDIR = joinpath(BUILDDIR, "tree-sitter-matlab")
const RUNTIMEDIR = joinpath(PKGROOT, "runtime")
const GRAMMAR_LIB = joinpath(RUNTIMEDIR, "libtree-sitter-matlab.$(Libdl.dlext)")
const DEPSFILE = joinpath(@__DIR__, "deps.jl")

"Locate the installed tree-sitter runtime; return its resolved path."
function find_runtime()
    for name in ("libtree-sitter.so.0", "libtree-sitter", "libtree-sitter.so")
        h = Libdl.dlopen_e(name)
        if h != C_NULL
            path = Libdl.dlpath(h)
            Libdl.dlclose(h)
            return path
        end
    end
    error(
        """
        Mjolnir: could not find the tree-sitter runtime (libtree-sitter).
        The pinned grammar needs ABI 15 -> tree-sitter >= 0.21 (0.25 known good).
        Install a recent runtime:
          macOS:          brew install tree-sitter
          from source:    git clone --depth 1 --branch v0.25.10 https://github.com/tree-sitter/tree-sitter
                          make -C tree-sitter && sudo make -C tree-sitter install PREFIX=/usr/local && sudo ldconfig
        NOTE: distro packages may be too old (Debian/Ubuntu `libtree-sitter0` is ABI 14 -> mismatch).
        """
    )
end

"Clone (if needed) and check out the pinned grammar revision."
function ensure_grammar()
    if !isdir(joinpath(GRAMMARDIR, ".git"))
        mkpath(BUILDDIR)
        rm(GRAMMARDIR; recursive = true, force = true)
        run(`git clone $GRAMMAR_URL $GRAMMARDIR`)
    end
    run(`git -C $GRAMMARDIR fetch --depth 1 origin $GRAMMAR_REV`)
    return run(`git -C $GRAMMARDIR checkout --quiet $GRAMMAR_REV`)
end

"Compile parser.c + external scanner.c into the grammar shared library."
function build_grammar()
    src = joinpath(GRAMMARDIR, "src")
    cc = get(ENV, "CC", "cc")
    mkpath(RUNTIMEDIR)
    return run(`$cc -O2 -shared -fPIC -I $src
         $(joinpath(src, "parser.c")) $(joinpath(src, "scanner.c"))
         -o $GRAMMAR_LIB`)
end

function write_deps(runtime_path)
    return open(DEPSFILE, "w") do io
        println(io, "# Auto-generated by deps/build.jl — do not edit.")
        println(io, "const LIBTREESITTER        = ", repr(runtime_path))
        println(io, "const LIBTREESITTER_MATLAB = ", repr(GRAMMAR_LIB))
        println(io, "const GRAMMAR_REV          = ", repr(GRAMMAR_REV))
    end
end

function main()
    runtime = find_runtime()
    ensure_grammar()
    build_grammar()
    write_deps(runtime)
    return @info "Mjolnir built" runtime grammar = GRAMMAR_LIB rev = GRAMMAR_REV
end

main()
